import{_ as e,o as a,c as d,a2 as r}from"./chunks/framework.HMsj64NP.js";const o="/unit_devlab_rp_examples/assets/rp2040pin.DEcPxM1-.png",i="/unit_devlab_rp_examples/assets/ch552.DKHVtD0z.jpg",C=JSON.parse('{"title":"Hardware: Microcontrolador, Pinout y Programador","description":"","frontmatter":{},"headers":[],"relativePath":"guide/hardware.md","filePath":"guide/hardware.md"}'),n={name:"guide/hardware.md"};function s(l,t,c,p,h,u){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="hardware-microcontrolador-pinout-y-programador" tabindex="-1">Hardware: Microcontrolador, Pinout y Programador <a class="header-anchor" href="#hardware-microcontrolador-pinout-y-programador" aria-label="Permalink to &quot;Hardware: Microcontrolador, Pinout y Programador&quot;">​</a></h1><p>Este documento describe el hardware sobre el que se ejecutan todos los ejemplos: el microcontrolador RP2040, la distribución de pines de la placa utilizada en el seminario, y el adaptador CH552 empleado para compilar, flashear y depurar los proyectos. Se recomienda revisar este documento antes de <a href="./devlab">Configuración del entorno</a> y de los <a href="./../examples/basic/00_blink">ejemplos básicos</a>.</p><h2 id="el-microcontrolador-rp2040" tabindex="-1">El microcontrolador: RP2040 <a class="header-anchor" href="#el-microcontrolador-rp2040" aria-label="Permalink to &quot;El microcontrolador: RP2040&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Valor</th></tr></thead><tbody><tr><td>Núcleos</td><td>2× ARM Cortex-M0+ (dual-core)</td></tr><tr><td>Frecuencia</td><td>Hasta 133 MHz (200 MHz a 1.15V)</td></tr><tr><td>SRAM</td><td>264 KB (en 6 bancos)</td></tr><tr><td>Memoria de programa</td><td>Externa, vía QSPI (flash NOR, típicamente 2 MB o más según la placa)</td></tr><tr><td>GPIO</td><td>30 pines de propósito general (GP0–GP29)</td></tr><tr><td>ADC</td><td>4 canales externos de 12 bits + 1 canal interno (sensor de temperatura)</td></tr><tr><td>Buses seriales</td><td>2× UART, 2× I²C, 2× SPI</td></tr><tr><td>PIO</td><td>2 bloques de Programmable I/O, 4 máquinas de estado cada uno</td></tr><tr><td>Referencia oficial</td><td><a href="https://datasheets.raspberrypi.com/rp2040/rp2040-datasheet.pdf" target="_blank" rel="noreferrer">RP2040 Datasheet</a></td></tr></tbody></table><p>A diferencia de otras familias de microcontroladores, el RP2040 no integra memoria flash en el mismo chip: el programa se ejecuta desde una memoria flash externa conectada por QSPI, cargada al iniciar mediante un bootloader en ROM. Esto es transparente para el desarrollo con el SDK, pero explica por qué el chip requiere una flash externa incluso en su presentación más mínima.</p><h2 id="placa-utilizada-en-el-seminario" tabindex="-1">Placa utilizada en el seminario <a class="header-anchor" href="#placa-utilizada-en-el-seminario" aria-label="Permalink to &quot;Placa utilizada en el seminario&quot;">​</a></h2><p>Las prácticas del Módulo II se desarrollan sobre una placa RP2040 con conector USB-C, distinta en factor de forma a la Raspberry Pi Pico oficial, aunque eléctricamente compatible: la asignación de buses por pin es la misma en ambas, por tratarse de una característica del propio chip y no de la placa.</p><h3 id="pinout-completo" tabindex="-1">Pinout completo <a class="header-anchor" href="#pinout-completo" aria-label="Permalink to &quot;Pinout completo&quot;">​</a></h3><div align="center"><img src="'+o+'" width="450px" alt="Development Board"><p><em>Development Board</em></p></div><table tabindex="0"><thead><tr><th>GPIO</th><th>I²C</th><th>SPI</th><th>UART</th><th>ADC</th><th>Notas</th></tr></thead><tbody><tr><td>GP0</td><td>I2C0 SDA</td><td>SPI0 RX (MISO)</td><td>UART0 TX</td><td>—</td><td></td></tr><tr><td>GP1</td><td>I2C0 SCL</td><td>SPI0 CSn</td><td>UART0 RX</td><td>—</td><td></td></tr><tr><td>GP2</td><td>I2C1 SDA</td><td>SPI0 SCK</td><td>UART0 CTS</td><td>—</td><td></td></tr><tr><td>GP3</td><td>I2C1 SCL</td><td>SPI0 TX (MOSI)</td><td>UART0 RTS</td><td>—</td><td></td></tr><tr><td>GP4</td><td>I2C0 SDA</td><td>SPI0 RX (MISO)</td><td>UART1 TX</td><td>—</td><td>Usado en los ejemplos de I²C (SDA)</td></tr><tr><td>GP5</td><td>I2C0 SCL</td><td>SPI0 CSn</td><td>UART1 RX</td><td>—</td><td>Usado en los ejemplos de I²C (SCL)</td></tr><tr><td>GP6</td><td>I2C1 SDA</td><td>SPI0 SCK</td><td>UART1 CTS</td><td>—</td><td></td></tr><tr><td>GP7</td><td>I2C1 SCL</td><td>SPI0 TX (MOSI)</td><td>UART1 RTS</td><td>—</td><td></td></tr><tr><td>GP8</td><td>I2C0 SDA</td><td>SPI1 RX (MISO)</td><td>UART1 TX</td><td>—</td><td></td></tr><tr><td>GP9</td><td>I2C0 SCL</td><td>SPI1 CSn</td><td>UART1 RX</td><td>—</td><td></td></tr><tr><td>GP10</td><td>I2C1 SDA</td><td>SPI1 SCK</td><td>UART1 CTS</td><td>—</td><td></td></tr><tr><td>GP11</td><td>I2C1 SCL</td><td>SPI1 TX (MOSI)</td><td>UART1 RTS</td><td>—</td><td></td></tr><tr><td>GP12</td><td>I2C0 SDA</td><td>SPI1 RX (MISO)</td><td>UART0 TX</td><td>—</td><td></td></tr><tr><td>GP13</td><td>I2C0 SCL</td><td>SPI1 CSn</td><td>UART0 RX</td><td>—</td><td></td></tr><tr><td>GP14</td><td>I2C1 SDA</td><td>SPI1 SCK</td><td>UART0 CTS</td><td>—</td><td>Usado como entrada digital en el ejemplo de botón</td></tr><tr><td>GP15</td><td>I2C1 SCL</td><td>SPI1 TX (MOSI)</td><td>UART0 RTS</td><td>—</td><td></td></tr><tr><td>GP16</td><td>I2C0 SDA</td><td>SPI0 RX (MISO)</td><td>UART0 TX</td><td>—</td><td>Usado en el ejemplo de SPI (MISO)</td></tr><tr><td>GP17</td><td>I2C0 SCL</td><td>SPI0 CSn</td><td>UART0 RX</td><td>—</td><td>Usado en el ejemplo de SPI (CS)</td></tr><tr><td>GP18</td><td>I2C1 SDA</td><td>SPI0 SCK</td><td>UART0 CTS</td><td>—</td><td>Usado en el ejemplo de SPI (SCK)</td></tr><tr><td>GP19</td><td>I2C1 SCL</td><td>SPI0 TX (MOSI)</td><td>UART0 RTS</td><td>—</td><td>Usado en el ejemplo de SPI (MOSI)</td></tr><tr><td>GP20</td><td>I2C0 SDA</td><td>SPI0 RX (MISO)</td><td>UART1 TX</td><td>—</td><td></td></tr><tr><td>GP21</td><td>I2C0 SCL</td><td>SPI0 CSn</td><td>UART1 RX</td><td>—</td><td></td></tr><tr><td>GP22</td><td>I2C1 SDA</td><td>SPI0 SCK</td><td>UART1 CTS</td><td>—</td><td></td></tr><tr><td>GP23</td><td>I2C1 SCL</td><td>SPI0 TX (MOSI)</td><td>UART1 RTS</td><td>—</td><td>Expuesto en esta placa; en la Pico oficial es de uso interno (control del regulador)</td></tr><tr><td>GP24</td><td>I2C0 SDA</td><td>SPI1 RX (MISO)</td><td>UART0 TX</td><td>—</td><td></td></tr><tr><td>GP25</td><td>I2C0 SCL</td><td>SPI1 CSn</td><td>UART0 RX</td><td>—</td><td><strong>LED integrado de la placa</strong> — evitar reasignarlo a un periférico</td></tr><tr><td>GP26</td><td>I2C1 SDA</td><td>SPI1 SCK</td><td>UART0 CTS</td><td>ADC0</td><td></td></tr><tr><td>GP27</td><td>I2C1 SCL</td><td>SPI1 TX (MOSI)</td><td>UART0 RTS</td><td>ADC1</td><td></td></tr><tr><td>GP28</td><td>I2C0 SDA</td><td>SPI1 RX (MISO)</td><td>UART1 TX</td><td>ADC2</td><td></td></tr><tr><td>GP29</td><td>I2C0 SCL</td><td>SPI1 CSn</td><td>UART1 RX</td><td>ADC3</td><td>Usado en el ejemplo de temperatura como referencia de canal externo</td></tr></tbody></table><blockquote><p>Cada GPIO admite varias funciones alternas, pero solo una a la vez: <code>gpio_set_function()</code> selecciona cuál está activa. La tabla anterior lista las opciones disponibles, no funciones simultáneas.</p></blockquote><h3 id="pines-y-elementos-adicionales-de-la-placa" tabindex="-1">Pines y elementos adicionales de la placa <a class="header-anchor" href="#pines-y-elementos-adicionales-de-la-placa" aria-label="Permalink to &quot;Pines y elementos adicionales de la placa&quot;">​</a></h3><p>Fuera de los 30 GPIO de propósito general, la placa expone lo siguiente:</p><table tabindex="0"><thead><tr><th>Elemento</th><th>Descripción</th></tr></thead><tbody><tr><td><code>3V3</code> / <code>Vin</code> / <code>Vout</code></td><td>Salida regulada de 3.3 V, entrada de alimentación externa, y salida de referencia respectivamente</td></tr><tr><td><code>VREF</code></td><td>Referencia de voltaje para el ADC, expuesta por separado para mediciones de mayor precisión</td></tr><tr><td><code>GND</code> (múltiples)</td><td>Distribuidos entre los GPIO para minimizar la longitud de retorno de corriente</td></tr><tr><td>Botón <code>BOOT</code></td><td>Fuerza el modo de arranque USB de almacenamiento masivo (BOOTSEL) al mantenerse presionado durante el reinicio</td></tr><tr><td>Botón <code>RST</code></td><td>Reinicio del microcontrolador</td></tr><tr><td>Botón <code>USR</code></td><td>Botón de propósito general, sin función reservada por el SDK</td></tr><tr><td>LED RGB direccionable</td><td>LED RGB Direccionable</td></tr><tr><td>LED <code>USR</code></td><td>LED de proposito general, sin función reservada por el SDK en GP25</td></tr><tr><td>Conector SWD (<code>3V3</code>, <code>SWDIO</code>, <code>GND</code>, <code>SWCLK</code>)</td><td>Puerto de depuración y programación de bajo nivel — ver sección siguiente</td></tr></tbody></table><h2 id="programador-y-depurador-ch552" tabindex="-1">Programador y depurador: CH552 <a class="header-anchor" href="#programador-y-depurador-ch552" aria-label="Permalink to &quot;Programador y depurador: CH552&quot;">​</a></h2><p>La compilación y carga de firmware descritas en <a href="./devlab">Configuración del entorno</a> mediante el modo BOOTSEL y arrastre del archivo <code>.uf2</code> es funcional, pero en el flujo de trabajo del seminario se utiliza un adaptador basado en el chip CH552 que esta basado en CMSIS-DAP,que puede cumplir dos funciones simultáneas sobre una misma conexión USB:</p><ol><li><strong>Depurador SWD compatible con CMSIS-DAP</strong>, usado por OpenOCD o PyOCD para compilar y cargar el firmware directamente, sin requerir el modo BOOTSEL manual.</li><li><strong>Puente USB-serial (CDC-ACM)</strong>, usado para observar la salida de <code>printf</code> cuando el proyecto no tiene habilitado el stdio nativo por USB.</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>En las practicas usaremos solo el <strong>Depurador SWD compatible con CMSIS-DAP</strong>, la función de puente USB serial, la delegaremos a la conexion usb integrada en nuestra tarjeta de desarrollo para poder evaluar la funcionalidad integrada de la misma.</p></div><h2 id="pinout" tabindex="-1">Pinout <a class="header-anchor" href="#pinout" aria-label="Permalink to &quot;Pinout&quot;">​</a></h2><div align="center"><img src="'+i+`" width="450px" alt="Development Board"><p><em>Development Board</em></p></div><h3 id="conexion" tabindex="-1">Conexión <a class="header-anchor" href="#conexion" aria-label="Permalink to &quot;Conexión&quot;">​</a></h3><p>El adaptador se conecta al conector SWD de 4 pines de la tarjeta de desarrollo:</p><table tabindex="0"><thead><tr><th>Adaptador CH552 JTAG</th><th>Adaptadpr CH552 SWD</th><th>Tarjeta RP2040</th></tr></thead><tbody><tr><td>3V3</td><td>3V3</td><td>3V3</td></tr><tr><td>TDO</td><td>SWDIO</td><td>SWDIO</td></tr><tr><td>GND</td><td>GND</td><td>GND</td></tr><tr><td>TDI(JTAG)</td><td>SWCLK</td><td>SWCLK</td></tr></tbody></table><h3 id="flasheo-mediante-openocd" tabindex="-1">Flasheo mediante OpenOCD <a class="header-anchor" href="#flasheo-mediante-openocd" aria-label="Permalink to &quot;Flasheo mediante OpenOCD&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openocd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> interface/cmsis-dap.cfg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> target/rp2040.cfg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;adapter speed 5000&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;program build/\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PROJECT_NAME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}.elf verify reset exit&quot;</span></span></code></pre></div><h3 id="descripcion-de-los-parametros" tabindex="-1">Descripción de los parámetros: <a class="header-anchor" href="#descripcion-de-los-parametros" aria-label="Permalink to &quot;Descripción de los parámetros:&quot;">​</a></h3><ul><li><strong><code>-f interface/cmsis-dap.cfg</code></strong>: Carga el archivo de configuración (<code>-f</code>) de la interfaz de hardware. Le indica a OpenOCD que se va a comunicar utilizando una sonda de depuración que sigue el estándar <strong>CMSIS-DAP</strong>.</li><li><strong><code>-f target/rp2040.cfg</code></strong>: Carga el archivo de configuración del <em>target</em>. Esto le proporciona a OpenOCD toda la información sobre el mapa de memoria y los registros específicos del microcontrolador <strong>RP2040</strong>.</li><li><strong><code>-c &quot;adapter speed 5000&quot;</code></strong>: Pasa un comando de configuración en crudo (<code>-c</code>) para establecer la velocidad del reloj de depuración (SWD) en <strong>5000 kHz (5 MHz)</strong>, asegurando una conexión rápida y estable.</li><li><strong><code>-c &quot;program ... verify reset exit&quot;</code></strong>: Ejecuta una secuencia automatizada de comandos en un solo paso: <ul><li><code>program build/\${PROJECT_NAME}.elf</code>: Escribe el binario ejecutable en la memoria flash del microcontrolador.</li><li><code>verify</code>: Lee la memoria recién flasheada y la compara con el archivo original para asegurar que no hubo errores en la escritura.</li><li><code>reset</code>: Envía una señal de reinicio al RP2040 para que arranque y empiece a ejecutar el nuevo firmware al instante.</li><li><code>exit</code>: Cierra el servidor de OpenOCD automáticamente en cuanto termina la secuencia, liberando la terminal.</li></ul></li></ul><h3 id="flasheo-mediante-pyocd" tabindex="-1">Flasheo mediante PyOCD <a class="header-anchor" href="#flasheo-mediante-pyocd" aria-label="Permalink to &quot;Flasheo mediante PyOCD&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pyocd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> flash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rp2040</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -f</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5000000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    build/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\${PROJECT_NAME}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.elf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span></code></pre></div><h3 id="descripcion-de-los-parametros-1" tabindex="-1">Descripción de los parámetros: <a class="header-anchor" href="#descripcion-de-los-parametros-1" aria-label="Permalink to &quot;Descripción de los parámetros:&quot;">​</a></h3><ul><li><strong><code>flash</code></strong>: Subcomando principal de pyOCD utilizado para borrar la memoria, escribir el nuevo binario y verificar que la carga se haya realizado correctamente.</li><li><strong><code>-t rp2040</code></strong>: Define el <em>target</em> o microcontrolador objetivo. Esto le indica a pyOCD cómo interactuar con el mapa de memoria específico del RP2040.</li><li><strong><code>-f 5000000</code></strong>: Configura la velocidad del reloj del adaptador de depuración (CMSIS-DAP) en Hz. <code>5000000</code> equivale a <strong>5 MHz</strong>, que ofrece un excelente balance entre velocidad de transferencia y estabilidad en las líneas de datos.</li><li><strong><code>build/\${PROJECT_NAME}.elf</code></strong>: Especifica la ruta hacia el archivo ejecutable generado por el compilador. Al usar el formato <code>.elf</code>, se conserva la información necesaria si deseas realizar depuración en tiempo real más adelante.</li></ul><p>Si <code>PICO_BOARD</code> está configurado como <code>pico2</code> o <code>pico2_w</code>, el archivo de destino cambia a <code>target/rp2350.cfg</code>, conforme a lo indicado en la <a href="./CMakeLists">referencia de CMakeLists.txt</a>.</p><h3 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Síntoma</th><th>Causa probable</th></tr></thead><tbody><tr><td>OpenOCD no detecta el adaptador</td><td>Cable o conexión SWD floja; verificar continuidad de las cuatro señales</td></tr><tr><td>En Windows, el dispositivo no es reconocido</td><td>Instalar el driver WinUSB para la interfaz CMSIS-DAP mediante <a href="https://zadig.akeo.ie/" target="_blank" rel="noreferrer">Zadig</a></td></tr><tr><td>El flasheo se completa pero no se observa salida por consola</td><td>El puerto serie del CH552 es distinto al de la interfaz de depuración; verificar qué puerto COM/ttyACM corresponde a cada función</td></tr><tr><td><code>program</code> falla con error de verificación</td><td>Placa no reiniciada correctamente tras un flasheo previo; desconectar y reconectar antes de reintentar</td></tr></tbody></table>`,34)])])}const S=e(n,[["render",s]]);export{C as __pageData,S as default};
